-- 1. Kiểm tra statistics quality
SELECT attname, n_distinct, correlation, most_common_vals, histogram_bounds
FROM pg_stats WHERE tablename = 'orders' AND attname = 'status';

-- 2. Tăng statistics target (default = 100 samples, max = 10000)
ALTER TABLE orders ALTER COLUMN status SET STATISTICS 500;
ANALYZE orders;

-- 3. Tune cost parameters cho SSD (default tối ưu cho HDD)
-- postgresql.conf hoặc ALTER SYSTEM:
ALTER SYSTEM SET random_page_cost = 1.1;  -- SSD: 1.1-1.5 (default 4.0)
ALTER SYSTEM SET effective_cache_size = '4GB';  -- RAM available cho OS cache
SELECT pg_reload_conf();

-- 4. Debug: tắt operators để test
SET enable_seqscan = off;  -- force index scan
SET enable_nestloop = off;  -- avoid nested loop
EXPLAIN SELECT * FROM orders WHERE status = 'pending';
-- Nếu plan tốt hơn → statistics issue, không phải missing index
SET enable_seqscan = on;

-- 5. pg_hint_plan (extension) — SQL Server-style hints
-- Cài đặt: shared_preload_libraries = 'pg_hint_plan'
SELECT /*+ IndexScan(orders idx_orders_status) */ *
FROM orders WHERE status = 'pending';

-- 6. Planner statistics cho join estimation
ALTER TABLE orders ALTER COLUMN customer_id SET STATISTICS 1000;
-- CREATE STATISTICS cho correlation giữa columns
CREATE STATISTICS orders_status_customer_stat ON status, customer_id
FROM orders;
ANALYZE orders;
